// ⚠️ Este fluxo NÃO executa otimizações - apenas valida dados

// ⚠️ Este fluxo valida se a API do Google Ads retornou dados reais para a campanha

const items = $input.all();

// 1. Verificar se houve resposta da requisição HTTP
if (!items || items.length === 0 || !items[0].json) {
  return {
    json: {
      has_data: false,
      data_source: 'google_ads_api',
      validation_status: 'no_request_response',
      reason: 'A requisição ao Google Ads falhou ou retornou vazio'
    }
  };
}

const data = items[0].json;

// 2. Tentar acessar o primeiro resultado do Google Ads
// O Google retorna um array 'results'. Se estiver vazio, não houve atividade no dia.
const googleData = data.results && data.results.length > 0 ? data.results[0] : null;

if (!googleData) {
  return {
    json: {
      ...data,
      has_data: false,
      validation_status: 'no_results',
      data_source: 'google_ads_api',
      reason: 'O Google Ads retornou 0 resultados para este ID de campanha nesta data'
    }
  };
}

// 3. Validar Campos Obrigatórios dentro da estrutura da API
// No Google Ads v22, os nomes são camelCase (ex: costMicros)
const metrics = googleData.metrics || {};
const requiredFields = ['impressions', 'clicks', 'costMicros'];
const missingFields = requiredFields.filter(field => 
  metrics[field] === null || metrics[field] === undefined
);

if (missingFields.length > 0) {
  return {
    json: {
      ...data,
      has_data: false,
      validation_status: 'incomplete',
      data_source: 'google_ads_api',
      missing_fields: missingFields,
      reason: `Campos de métricas ausentes no retorno da API: ${missingFields.join(', ')}`
    }
  };
}

// 4. Dados válidos e prontos para o cálculo
return {
  json: {
    ...data,
    has_data: true,
    validation_status: 'valid',
    // Usamos a data que foi tentada no fluxo (D-1 ou D-2)
    date_used: data.attempted_date || data.date_d1, 
    data_source: 'google_ads_api',
    fallback_used: !!data.fallback_active
  }
};

// Nome: "Valida Dados - Meta"
const items = $input.all();

if (!items || items.length === 0 || !items[0].json.data || items[0].json.data.length === 0) {
  return {
    json: {
      ...items[0]?.json,
      has_data: false,
      data_source: 'meta_ads_api',
      validation_status: 'no_results',
      reason: 'O Meta Ads retornou 0 resultados para esta data'
    }
  };
}

// Se chegou aqui, existe dado no array 'data'
return {
  json: {
    ...items[0].json,
    has_data: true,
    validation_status: 'valid',
    data_source: 'meta_ads_api',
    date_used: items[0].json.date_d1 // ou date_d2 se for fallback
  }
};

const items = $input.all();
const output = [];

for (const item of items) {
  const root = item.json;
  // No Meta, os dados reais de métricas estão em root.data[0]
  const data = (root.data && root.data.length > 0) ? root.data[0] : null;

  if (!data) {
    output.push(item);
    continue;
  }

  // 1. Extração de Métricas (Convertendo texto para número)
  const cost = Number(data.spend || 0);
  const impressions = Number(data.impressions || 0);
  const clicks = Number(data.clicks || 0);

  // 2. Tratamento de Conversões (Array de Actions)
  let conversions = 0;
  if (data.actions && Array.isArray(data.actions)) {
    // Procuramos pelo tipo de conversão que você usa (ex: compra ou conversão padrão)
    const convAction = data.actions.find(a => 
      a.action_type === 'offsite_conversion.fb_pixel_purchase' || 
      a.action_type === 'conversions' ||
      a.action_type === 'purchase'
    );
    conversions = convAction ? Number(convAction.value) : 0;
  }

  // 3. Cálculos de Performance
  const ctr = impressions > 0 ? (clicks / impressions) * 100 : 0;
  const cpc = clicks > 0 ? cost / clicks : 0;
  const cpa = conversions > 0 ? cost / conversions : 0;
  const convRate = clicks > 0 ? (conversions / clicks) * 100 : 0;

  output.push({
    json: {
      ...root, // Preserva IDs do Notion e contexto
      calculado: {
        custo_real: parseFloat(cost.toFixed(2)),
        impressoes: impressions,
        cliques: clicks,
        conversoes: conversions,
        todas_conversoes: conversions,
        cpa_atual: parseFloat(cpa.toFixed(2)),
        cpa_alvo_google: Number(root.meta_valor || 0), // Meta comparativa do Notion
        taxa_conversao: parseFloat(convRate.toFixed(2)),
        ctr: parseFloat(ctr.toFixed(2)),
        cpc: parseFloat(cpc.toFixed(2)),
        score_otimizacao: "N/A", 
        status_aprendizado: data.learning_stage_info?.status || 'N/A'
      }
    }
  });
}

return output;

// ⚠️ Este fluxo NÃO executa otimizações - apenas valida dados

// Nome: "Valida Dados - Meta"
const items = $input.all();

if (!items || items.length === 0 || !items[0].json.data || items[0].json.data.length === 0) {
  return {
    json: {
      ...items[0]?.json,
      has_data: false,
      data_source: 'meta_ads_api',
      validation_status: 'no_results',
      reason: 'O Meta Ads retornou 0 resultados para esta data'
    }
  };
}

// Se chegou aqui, existe dado no array 'data'
return {
  json: {
    ...items[0].json,
    has_data: true,
    validation_status: 'valid',
    data_source: 'meta_ads_api',
    date_used: items[0].json.date_d1 // ou date_d2 se for fallback
  }
};

const items = $input.all();
const output = [];

for (const item of items) {
  const data = item.json;

  // 1. Pega a Meta e o Tipo que vieram do Notion (estão na raiz do item atual)
  // Ajustado para os nomes exatos que você tem no seu retorno
  const metaValor = data.meta_valor || 0;
  const tipoMetrica = data.sop_config?.metric_principal || "CPA";

  // 2. Busca os dados reais olhando para o nó "D7" (que é sua base de 7 dias)
  // Usamos try/catch para evitar erro se o nó não for encontrado
  let raw = { cost: 0, conversions: 0, convValue: 0, clicks: 0, impressions: 0, optScore: 0, budget: 0, status: "ESTÁVEL" };

  try {
    const d7Node = $("HTTP Request Google Ontem (D7)").first().json;
    const res = d7Node.results?.[0] || {};
    const m = res.metrics || {};
    const c = res.campaign || {};
    const b = res.campaignBudget || {};

    raw = {
      cost: Number(m.costMicros || 0) / 1000000,
      conversions: Number(m.conversions || 0),
      convValue: Number(m.conversionsValue || 0),
      clicks: Number(m.clicks || 0),
      impressions: Number(m.impressions || 0),
      optScore: Number(c.optimizationScore || 0) * 100,
      budget: Number(b.amountMicros || 0) / 1000000,
      status: c.biddingStrategySystemStatus || "ESTÁVEL"
    };
  } catch (e) {
    // Se não encontrar o nó D7, ele usará o raw zerado acima
  }

  // 3. Calculadora de Valor Real
  const calcular = (r, tipo) => {
    if (tipo === 'CPA') return r.conversions > 0 ? (r.cost / r.conversions) : 0;
    if (tipo === 'ROAS') return r.cost > 0 ? (r.convValue / r.cost) : 0;
    if (tipo === 'CPC') return r.clicks > 0 ? (r.cost / r.clicks) : 0;
    if (tipo === 'CTR') return r.impressions > 0 ? (r.clicks / r.impressions) * 100 : 0;
    return 0;
  };

  const valorReal = calcular(raw, tipoMetrica);

  // 4. Status da Meta
  let statusMeta = "No Alvo ✅";
  if (metaValor > 0) {
    if (tipoMetrica === "CPA" || tipoMetrica === "CPC") {
      statusMeta = valorReal <= metaValor ? "No Alvo ✅" : "Acima da Meta ❌";
    } else {
      statusMeta = valorReal >= metaValor ? "No Alvo ✅" : "Abaixo da Meta ❌";
    }
  }

  output.push({
    json: {
      ...data,
      valor_real: parseFloat(valorReal.toFixed(2)),
      meta_estabelecida: metaValor,
      status_meta: statusMeta,
      orcamento_diario: raw.budget,
      aprendizado: raw.status.replace(/_/g, " "),
      opt_score: parseFloat(raw.optScore.toFixed(2))
    }
  });
}

return output;

// ⚠️ Este fluxo NÃO executa otimizações - apenas calcula desvio para classificação
// ⚠️ Este fluxo calcula desvio para classificação e busca dados no histórico se necessário
const items = $input.all();
const returnData = [];

for (const item of items) {
  const data = item.json;

  // 1. Configurações Iniciais
  const config = data.sop_config || {};
  const meta = Number(config.meta_valor || data.meta_valor || 0);
  const tipo = config.metric_principal || data.tipo_metrica || 'CPA';

  // 2. Tenta ler as métricas do Input atual
  let v_d1 = Number(data.v_d1 ?? data.calc_context?.v_d1 ?? 0);
  let v_3d = Number(data.v_3d ?? data.calc_context?.v_3d ?? 0);
  let v_7d = Number(data.v_7d ?? data.calc_context?.v_7d ?? 0);

  // -------------------------------------------------------------
  // 3. BÓIA DE SALVAÇÃO: Se tudo for zero, busca no nó "Unificar"
  // -------------------------------------------------------------
  if (v_d1 === 0 && v_3d === 0 && v_7d === 0) {
    try {
      // Tenta buscar no nó que gerou os dados. 
      // Verifique se o nome abaixo é EXATAMENTE o nome do seu nó de unificação
      const unificado = $("Code Unificar Períodos (D1, 3D, 7D)").first().json;

      v_d1 = Number(unificado.v_d1 || 0);
      v_3d = Number(unificado.v_3d || 0);
      v_7d = Number(unificado.v_7d || 0);
    } catch (e) {
      // Se não achar o nó pelo nome, tenta pegar do nó Cálcula Métricas se existir
      try {
         const calculo = $("Code Cálcula Métricas").first().json;
         v_d1 = Number(calculo.v_d1 || 0);
         v_3d = Number(calculo.v_3d || 0);
         v_7d = Number(calculo.v_7d || 0);
      } catch (e2) {}
    }
  }

  // 4. Bloqueio de segurança REAL
  // Só para se realmente a meta for 0 E não tivermos conseguido recuperar os dados
  if (meta === 0 && (v_d1 === 0 && v_3d === 0 && v_7d === 0)) {
    returnData.push({
      json: {
        ...data,
        analise_desvios: { error: "Meta não definida ou dados não encontrados" },
        deviation_status: 'missing_data_for_calculation'
      }
    });
    continue;
  }

  // 5. Funções de Cálculo (CPA: Menor é melhor / ROAS: Maior é melhor)
  const calcDesvio = (valor, meta, tipoMetrica) => {
    if (meta === 0 || valor === 0) return 0;

    // Se for ROAS, CTR, Taxa de Conversão: Maior que a meta é positivo
    if (["ROAS", "CTR", "Taxa de Conversão"].includes(tipoMetrica)) {
       // Ex: Meta 5, Valor 6. ((6-5)/5)*100 = +20% (Bom)
       return ((valor - meta) / meta) * 100;
    }

    // Se for CPA, CPC: Maior que a meta é negativo (ruim)
    // Ex: Meta 10, Valor 12. Invertemos sinal para indicar que excedeu?
    // Padrão de Desvio simples: ((Valor - Meta) / Meta) * 100
    // Ex: Meta 10, Valor 15 = +50% (50% acima da meta, ou seja, ruim)
    return ((valor - meta) / meta) * 100;
  };

  const calcTendencia = (v3, v7) => {
    if (!v7 || v7 === 0) return 0;
    return ((v3 - v7) / v7) * 100;
  };

  // 6. Executa os cálculos
  const d1_res = calcDesvio(v_d1, meta, tipo);
  const d3_res = calcDesvio(v_3d, meta, tipo);
  const d7_res = calcDesvio(v_7d, meta, tipo);
  const tend_res = calcTendencia(v_3d, v_7d);

  returnData.push({
    json: {
      ...data,
      // Garante que v_d1, v_3d, v_7d passem para o próximo nó
      v_d1, v_3d, v_7d, 
      analise_desvios: {
        meta_aplicada: meta,
        tipo_metric: tipo,
        d1: { valor: v_d1, desvio: parseFloat(d1_res.toFixed(2)) },
        d3: { valor: v_3d, desvio: parseFloat(d3_res.toFixed(2)) },
        d7: { valor: v_7d, desvio: parseFloat(d7_res.toFixed(2)) },
        tendencia_3d_vs_7d: parseFloat(tend_res.toFixed(2))
      },
      deviation_status: 'calculated_success'
    }
  });
}

return returnData;

// ⚠️ DECLARAÇÃO EXPLÍCITA: Este fluxo NÃO executa otimizações
// Classificação é APENAS informativa e serve para registro histórico
const items = $input.all();
const output = [];

for (const item of items) {
  const data = item.json;

  // 1. Acessar os dados calculados no nó anterior
  const analise = data.analise_desvios;
  const config = data.sop_config;

  // Validação de segurança: se não houver análise, define como Sem Dados
  if (!analise || !analise.d7) {
    output.push({
      json: {
        ...data,
        final_status: "Sem Dados",
        final_score: 0,
        classe_score: "N/A",
        status_emoji: "⚪"
      }
    });
    continue;
  }

  const d7 = analise.d7.desvio;
  const d1 = analise.d1.desvio;
  const tendencia = analise.tendencia_3d_vs_7d;
  const meta = config.meta_valor;

  let status = "OK";
  let score = 100;

  // --- REGRA CENTRAL DE STATUS ---

  // Passo 3: Classificação Base (7D)
  if (d7 <= 0) {
    status = "OK";
  } else if (d7 <= 15) {
    status = "Atenção";
  } else {
    status = "Crítico";
  }

  // Passo 4: Ajuste por Tendência
  // Se Status é OK mas tendência piorou > 10%, rebaixa.
  // Nota: Para CPA "piorar" é positivo (subiu), para ROAS "piorar" é negativo.
  // Como nosso nó anterior já padronizou desvios, "tendencia > 10" sempre significa "piorou".
  if (status === "OK" && tendencia > 10) {
    status = "Atenção";
  }

  // Passo 5: Ajuste por D-1 (Alerta Pontual)
  if (d1 > 30 && status === "OK") {
    status = "Atenção";
  }

  // --- CÁLCULO DO SCORE INTERNO (0-100) ---

  // Penalidade por desvio 7D (Peso 50%)
  // Se o desvio for 20%, subtrai 40 pontos. Máximo 40 de penalidade.
  score -= Math.min(d7 * 2, 40);

  // Penalidade por tendência negativa (Peso 30%)
  if (tendencia > 0) {
    score -= Math.min(tendencia, 30);
  }

  // Penalidade por D-1 extremo (Peso 20%)
  if (d1 > 20) {
    score -= 10;
  }

  // Garantir que o score não seja negativo
  score = Math.max(Math.round(score), 0);

  // Classificação do Score
  let classeScore = "Crítico";
  if (score >= 80) classeScore = "Estável";
  else if (score >= 60) classeScore = "Atenção";
  else if (score >= 40) classeScore = "Instável";

  // Definir Emoji
  const emojiMap = { "OK": "✅", "Atenção": "🟡", "Crítico": "🔴", "Sem Dados": "⚪" };

  output.push({
    json: {
      ...data,
      final_status: status,
      final_score: score,
      classe_score: classeScore,
      status_emoji: emojiMap[status] || "⚪"
    }
  });
}

return output;

