// Captura o item que vem do loop/notion
const item = $input.first();
const data = item.json;
console.log("Campos disponíveis:", Object.keys(data));
// 1. Função de Extração Robusta
// O Notion pode enviar como: data.prop.number OU data.properties.prop.number
const extrairValorNotion = (nomeCampo) => {
  const campo = data[nomeCampo] || (data.properties ? data.properties[nomeCampo] : null);

  if (!campo) return 0;

  // Se for um campo do tipo 'number' no Notion
  if (typeof campo === 'object' && campo.hasOwnProperty('number')) {
    return Number(campo.number || 0);
  }

  // Se for um campo que já veio limpo como número ou string
  return Number(campo || 0);
};

// 2. Definição da Meta e Métrica
//const meta_valor = extrairValorNotion("Meta 1ª Numérica");

// Extrair o Tipo da Métrica (lidando com campos de Select do Notion)
let metric_principal = "CPA";
const campoTipo = data["Tipo da Métrica"] || (data.properties ? data.properties["Tipo da Métrica"] : null);

if (campoTipo) {
  metric_principal = campoTipo.select ? campoTipo.select.name : (typeof campoTipo === 'string' ? campoTipo : "CPA");
}
const meta_valor = $('Edit Fields').first().json.meta_valor || 0;
// 3. Configuração dos Limiares do SOP
const sop_thresholds = {
  'CPA': { ok_limit: 0, attention_limit: 15, critical_limit: 15, trend_alert: 10, d1_alert: 30 },
  'ROAS': { ok_limit: 0, attention_limit: 15, critical_limit: 15, trend_alert: 10, d1_alert: 30 }
};

return {
  json: {
    ...data,
    sop_config: {
      metric_principal: metric_principal,
      //meta_valor: meta_valor,
      meta_valor: meta_valor,
      thresholds: sop_thresholds[metric_principal] || sop_thresholds['CPA']
    }
  }
};

