    date_d1: formatDate(d1),
    date_d2: formatDate(d2),
    date_d1_iso: d1.toISOString(),
    date_d2_iso: d2.toISOString(),
    timezone: timezone,

    // --- CONTROLE ---
    fallback_active: false,
    execution_timestamp: now.toISOString(),

    // --- DADOS BRUTOS (para auditoria, se necessário) ---
    raw_notion_data: data
  }
};

// 1. Obter os dados de entrada do nó anterior
const items = $input.all();

// 2. Criar um array para armazenar os resultados limpos
const outputItems = [];

// --- Funções Auxiliares ---

// Função para extrair texto simples de Rich Text (para Text e Rich Text)
const extractRichText = (richTextArray) => {
    if (!richTextArray || richTextArray.length === 0) {
        return '';
    }
    const textSegments = richTextArray.map(segment => segment.plain_text);
    return textSegments.join('');
};

// Função para extrair nomes de Multi-Select
const extractMultiSelectNames = (multiSelectArray) => {
    if (!multiSelectArray || multiSelectArray.length === 0) {
        return '';
    }
    const names = multiSelectArray.map(option => option.name);
    return names.join(', '); // Retorna os nomes separados por vírgula
};

for (const item of items) {
    const properties = item.json.properties;

    // --- 1. Extração de Fórmulas (Retornam String ou Number) ---
    const idCampanha = properties['id_campanha']?.formula?.string || '';
    const nomeCampanha = properties['Nome Campanha']?.formula?.string || '';
    const notionIdCamp = properties['notion_id_camp']?.formula?.string || '';
    const tskItensChkList = properties['tsk_itens_chkList']?.formula?.number || 0; // Novo

    // --- 2. Extração de Números Simples ---
    const orcamentoDiario = properties['Orçamento Diário']?.number || 0;
    const cpaAlvo = properties['CPA Alvo']?.number || 0;
    const cpaCampanha = properties['CPA da Campanha']?.number || 0;
    const ctrCampanha = properties['CTR da Campanha']?.number || 0;
    const cpcCampanha = properties['CPC da Campanha']?.number || 0; // Novo
    const impressoes = properties['Impressões']?.number || 0; // Novo
    const resultadoAtual = properties['Resultado Atual (Métrica-mãe)']?.number || 0; // Novo
    const taxaConversao = properties['Taxa de Conversão']?.number || 0; // Novo
    // Nota: Removi a duplicata de metaNumerica que existia no seu código anterior
    const metaNumerica = properties['Meta da Métrica-mãe']?.number || 0;
    const idGoogle = properties['id_google_camp']?.number || 0;
    const idClientGoogle = properties['id_google_account']?.number || 0;
    const idMetaAccount = properties['id_meta_account']?.number || 0;
    const idMetaCampaign = properties['id_meta_camp']?.number || 0;
    const idMetaAds = properties['ID Meta Ads']?.number || 0;

    // --- 3. Extração de Rollups (Campos Calculados/Agregados) ---
    // O Notion retorna Rollups de formas diferentes (Number, Array, etc.)
    const totalInvestidoCampanha = properties['Total Investido Campanha']?.rollup?.number || 0;

    // Rollup que retorna array de fórmulas (tsk_itens_concluídos) - pega o primeiro item
    let tskItensConcluidos = '0';
    if (properties['tsk_itens_concluídos']?.rollup?.array?.[0]?.formula?.string) {
        tskItensConcluidos = properties['tsk_itens_concluídos'].rollup.array[0].formula.string;
    }

    // --- 4. Extração de Select e Status (Seleção Única) ---
    const estrategia = properties['Estratégia']?.select?.name || '';
    const objetivo = properties['Objetivo']?.select?.name || '';
    const estagioFunil = properties['Estágio do Funil']?.select?.name || '';
    const modeloNegocio = properties['Modelo de Negócio']?.select?.name || ''; // Novo
    const statusAprendizagem = properties['Status Aprendizagem']?.select?.name || ''; // Novo
    // Campo Status é diferente de Select no objeto JSON
    const status = properties['Status']?.status?.name || ''; // Novo

    // --- 5. Extração de Multi-Select (Seleção Múltipla) ---
    const plataforma = extractMultiSelectNames(properties['Fonte']?.multi_select);
    const metricaPrimaria = extractMultiSelectNames(properties['Métrica-Mãe']?.multi_select);
    const metricaSecundaria = extractMultiSelectNames(properties['Métrica Secundária']?.multi_select);
    const canais = extractMultiSelectNames(properties['Canais']?.multi_select);
    // Atenção: No seu JSON o campo chama "Tipo de campanha" (c minúsculo) ou "Tipo de Campanha"? 
    // Ajustei para o que veio no JSON: "Tipo de campanha"
    const tipoCampanha = extractMultiSelectNames(properties['Tipo de campanha']?.multi_select); 
    const publicoAlvo = extractMultiSelectNames(properties['Públicos-alvo']?.multi_select);

    // --- 6. Extração de Texto (Rich Text) ---
    const produtoServico = extractRichText(properties['Produto/Serviço']?.rich_text);
    const geografia = extractRichText(properties['Geografia']?.rich_text);
    const objetivoCampanha = extractRichText(properties['Objetivo da Campanha']?.rich_text);
    const siglaCliente = extractRichText(properties['client_slug']?.rich_text); // Novo
    const periodoVersao = extractRichText(properties['Período/Versão']?.rich_text); // Novo

    // --- 7. Extração de Checkbox (Booleanos) ---
    const periodoOtimizacaoAberto = properties['Otimização Ativa?']?.checkbox || false; // Novo
    const metaDentroEstabelecido = properties['Meta dentro do Estabelecido']?.checkbox || false; // Novo

    // --- 8. Extração de Datas ---
    const dataInicio = properties['Data de Inicio']?.date?.start || '';
    const dataConclusao = properties['Data de conclusão']?.date?.start || '';
    const ultimaOtimizacao = properties['Última Otimização']?.date?.start || '';

    // --- 9. Extração de Unique ID ---
    // Tratamento seguro para evitar erro de undefined
    const prefix = properties['id_camp_padrao']?.unique_id?.prefix || '';
    const number = properties['id_camp_padrao']?.unique_id?.number || '';
    const idCampPadrao = prefix && number ? `${prefix}-${number}` : (prefix + number);

    // --- 10. Criação do novo objeto com as propriedades limpas ---
    const newItem = {
        json: {
            // IDs e Identificadores
            clean_id_campanha: idCampanha,
            clean_notion_id_camp: notionIdCamp,
            clean_id_camp_padrao: idCampPadrao,
            clean_id_google: idGoogle,
            clean_id_customer_google: idClientGoogle,
            clean_id_meta_account: idMetaAccount,
            clean_id_meta_campaign: idMetaCampaign,
            clean_id_meta_ads: idMetaAds,
            clean_client_slug: siglaCliente,

            // Informações da Campanha
            clean_nome_campanha: nomeCampanha,
            clean_status: status,
            clean_plataforma: plataforma, // Fonte
            clean_tipo_campanha: tipoCampanha,
            clean_estrategia: estrategia,
            clean_objetivo: objetivo,
            clean_objetivo_campanha: objetivoCampanha,
            clean_produto_servico: produtoServico,
            clean_geografia: geografia,
            clean_canais: canais,
            clean_modelo_negocio: modeloNegocio,
            clean_estagio_funil: estagioFunil,
            clean_status_aprendizagem: statusAprendizagem,
            clean_periodo_versao: periodoVersao,

            // Métricas Financeiras
            clean_orcamento_diario: orcamentoDiario,
            clean_total_investido: totalInvestidoCampanha,
            clean_cpa_alvo: cpaAlvo,
            clean_cpa_campanha: cpaCampanha,
            clean_cpc_campanha: cpcCampanha,

            // Métricas de Performance
            clean_impressoes: impressoes,
            clean_ctr_campanha: ctrCampanha,
            clean_taxa_conversao: taxaConversao,
            clean_resultado_metrica_mae: resultadoAtual,
            clean_meta_metrica_mae: metaNumerica,
            clean_metrica_mae: metricaPrimaria,
            clean_meta_secundaria: metricaSecundaria,

            // Checkboxes e Tarefas
            clean_periodo_otimizacao_aberto: periodoOtimizacaoAberto,
            clean_meta_dentro_estabelecido: metaDentroEstabelecido,
            clean_tsk_itens_chkList: tskItensChkList,
            clean_tsk_itens_concluidos: tskItensConcluidos,
            clean_publico_alvo: publicoAlvo,

            // Datas
            clean_data_inicio: dataInicio,
            clean_data_conclusao: dataConclusao,
            clean_ultima_otimizacao: ultimaOtimizacao,
        },
        binary: item.binary,
    };
    outputItems.push(newItem);
}

return outputItems;

