// 1. Captura os dados dos nós da série
const d1 = $("HTTP Request Google Ontem (D1)").first().json;
const d3 = $("HTTP Request Google Ontem (D3)").first().json;
const d7 = $("HTTP Request Google Ontem (D7)").first().json;

// Função para calcular CPA ou ROAS
const calcularValor = (data, tipo) => {
  const metrics = data.results?.[0]?.metrics || {};
  const cost = Number(metrics.costMicros || 0) / 1000000;
  const conv = Number(metrics.conversions || 0);
  const val = Number(metrics.conversionsValue || 0);

  if (tipo === "ROAS") return cost > 0 ? val / cost : 0;
  return conv > 0 ? cost / conv : 0;
};

// ── Item #7: extrai métricas brutas para BigQuery ────────────
const extractRaw = (data) => {
  const m = data.results?.[0]?.metrics || {};
  return {
    cost:        Number(m.costMicros  || 0) / 1_000_000,
    clicks:      Number(m.clicks      || 0),
    impressions: Number(m.impressions || 0),
  };
};
const raw_d1 = extractRaw(d1);
const raw_d3 = extractRaw(d3);
const raw_d7 = extractRaw(d7);

// 2. Configurações
const config = d7.sop_config || {};
const tipo = config.metric_principal || "CPA";

// 3. Extrai os valores reais
const v_d1 = calcularValor(d1, tipo);
const v_3d = calcularValor(d3, tipo);
const v_7d = calcularValor(d7, tipo);

// 4. Função Mágica de Formatação: XX% (YY)
const formatarTendencia = (valorAtual, valorBase) => {
  if (!valorAtual || !valorBase || valorBase === 0) return "0.00% (R$0.00)";
  const diffAbsoluta = valorAtual - valorBase;
  const diffPercentual = (diffAbsoluta / valorBase) * 100;
  return `${diffPercentual.toFixed(2)}% (R$ ${diffAbsoluta.toFixed(2)})`;
};

const txt_tendencia_3d = formatarTendencia(v_3d, v_7d);
const txt_tendencia_1d = formatarTendencia(v_d1, v_7d);

// 5. Optimization Score
const optScoreRaw = d7.results?.[0]?.campaign?.optimizationScore || 0;
const optScoreFormatted = parseFloat((optScoreRaw * 100).toFixed(2));

// 6. Retorno Final
return {
  json: {
    ...d7,
    v_d1: parseFloat(v_d1.toFixed(2)),
    v_3d: parseFloat(v_3d.toFixed(2)),
    v_7d: parseFloat(v_7d.toFixed(2)),

    txt_tendencia_3d: txt_tendencia_3d,
    txt_tendencia_1d: txt_tendencia_1d,

    val_tendencia_3d: parseFloat(((v_3d - v_7d) / (v_7d || 1) * 100).toFixed(2)),

    opt_score: optScoreFormatted,

    calc_context: {
      v_d1, v_3d, v_7d,
      txt_tendencia_3d,
      txt_tendencia_1d
    },

    // ── Métricas brutas para BigQuery (Item #7 corrigido) ──
    raw_cost_d1:        parseFloat(raw_d1.cost.toFixed(6)),
    raw_clicks_d1:      raw_d1.clicks,
    raw_impressions_d1: raw_d1.impressions,
    raw_cost_3d:        parseFloat(raw_d3.cost.toFixed(6)),
    raw_cost_7d:        parseFloat(raw_d7.cost.toFixed(6)),
  }
};

